# The virtual bash seems to reset arrays between statements in the same session.
# Let's try a fully self-contained single-command approach using awk instead.

awk '
BEGIN { FS="="; OFS="=" }

# Helper to trim whitespace
function trim(s) {
  gsub(/^[ \t]+|[ \t]+$/, "", s)
  return s
}

# Parse a file; pass=1 for defaults, pass=2 for custom
FNR == 1 { pass++ }

/^\[.*\]/ {
  sec = $0
  gsub(/^\[|\]$/, "", sec)
  sec = trim(sec)
  # Record section order on first encounter (pass 1 first)
  if (!(sec in sec_seen)) {
    sec_order[++sec_count] = sec
    sec_seen[sec] = 1
  }
  next
}

/^[[:space:]]*$/ || /^[;#]/ { next }

/=/ {
  key = trim($1)
  val = $0; sub(/^[^=]*=/, "", val)   # everything after the first "="

  combo = sec SUBSEP key

  # Track key order per section (once only)
  if (!(combo in key_seen)) {
    key_seen[combo] = 1
    key_order[sec] = key_order[sec] "|" key
  }

  # Custom (pass 2) always wins; defaults (pass 1) only if not yet set
  if (pass == 2 || !(combo in data)) {
    data[combo] = val
  }
}

END {
  out = "/config/merged.ini"
  for (s = 1; s <= sec_count; s++) {
    sec = sec_order[s]
    if (s > 1) printf "\n" > out
    printf "[%s]\n", sec > out
    n = split(key_order[sec], keys, "|")
    for (k = 1; k <= n; k++) {
      if (keys[k] == "") continue
      printf "%s=%s\n", keys[k], data[sec SUBSEP keys[k]] > out
    }
  }
  close(out)
  print "✅  Written to /config/merged.ini"
}
' /config/defaults.ini /config/custom.ini

echo ""
echo "========== /config/merged.ini =========="
cat /config/merged.ini

# Pipe literal seems unsupported in awk string context in this env.
# Use a different delimiter — comma — for key_order tracking.

awk '
BEGIN { FS="="; OFS="=" }

function trim(s,    t) {
  t = s
  gsub(/^[ \t]+/, "", t)
  gsub(/[ \t]+$/, "", t)
  return t
}

FNR == 1 { pass++ }

/^\[.*\]$/ {
  sec = substr($0, 2, length($0)-2)
  sec = trim(sec)
  if (!(sec in sec_seen)) {
    sec_count++
    sec_order[sec_count] = sec
    sec_seen[sec] = 1
    key_count[sec] = 0
  }
  next
}

/^[ \t]*$/ { next }
/^[;#]/    { next }

{
  eq = index($0, "=")
  if (eq == 0) next
  key = trim(substr($0, 1, eq-1))
  val =      substr($0, eq+1)

  combo = sec SUBSEP key
  if (!(combo in key_seen)) {
    key_seen[combo] = 1
    kc = ++key_count[sec]
    sec_keys[sec, kc] = key
  }
  if (pass == 2 || !(combo in data)) {
    data[combo] = val
  }
}

END {
  out = "/config/merged.ini"
  for (si = 1; si <= sec_count; si++) {
    s = sec_order[si]
    if (si > 1) printf "\n" > out
    printf "[%s]\n", s > out
    for (ki = 1; ki <= key_count[s]; ki++) {
      k = sec_keys[s, ki]
      printf "%s=%s\n", k, data[s SUBSEP k] > out
    }
  }
  close(out)
}
' /config/defaults.ini /config/custom.ini

echo "✅  Merged INI written to /config/merged.ini"
echo ""
echo "========== /config/merged.ini =========="
cat /config/merged.ini

